// Latch each MQTT message into flow.bms_state[bank][field] = {value, _ts}.
const parts = msg.topic.split('/');
const bank = parts[0];
const field = parts.slice(1).join('/');
if (!field) return null;  // skip bare-topic messages (no field)

const state = flow.get('bms_state') || {};
const bankState = state[bank] || {};
bankState[field] = { value: msg.payload, _ts: Date.now() };
state[bank] = bankState;
flow.set('bms_state', state);
return null;

// Per-tick health checks with per-condition debounce.
//   - Statistical checks (default {active:3, clear:3}) require 3 consecutive
//     ticks (~9min @ 180s) before flipping state — suppresses BMS noise.
//   - Safety-critical checks ({active:1, clear:3}) emit 'active' on the first
//     tick the condition holds, but require 3 clear ticks before resolving.
//   - Events (bms_reboot, cycles_reset) emit one-shot, no debounce.
// Out 1 = alerts (one msg per emit, topic=checkbattery/alert)
// Out 2 = influx batch (single msg with payload=[points...])

const NOW = Date.now();
const NOW_ISO = new Date(NOW).toISOString();
const BANKS = ['bat_ost', 'bat_west', 'bat_big'];

const STATE = flow.get('bms_state') || {};
const PREV  = flow.get('bms_prev') || {};
const DB    = flow.get('bms_debounce') || {};

const TH = {
    cell_delta_warn:  0.050,
    cell_delta_alert: 0.100,
    cell_min:         2.80,
    cell_max:         3.60,
    cell_outlier:     0.030,
    temp_min:         -10,
    temp_max:         50,
    mosfet_temp_max:  60,
    comm_dropout_ms:  3 * 60 * 1000
};

const DEBOUNCE = {
    no_data:               { active: 1, clear: 3 },
    comm_dropout:          { active: 1, clear: 3 },
    cell_under:            { active: 1, clear: 3 },
    cell_over:             { active: 1, clear: 3 },
    switch_charge_off:     { active: 1, clear: 3 },
    switch_discharge_off:  { active: 1, clear: 3 }
};
const DEBOUNCE_DEFAULT = { active: 3, clear: 3 };

const alerts = [];
const points = [];

function num(v) {
    if (v === undefined || v === null) return null;
    const n = parseFloat(v);
    return Number.isFinite(n) ? n : null;
}

// hold=true: condition currently violating; hold=false: currently OK.
function condition(bank, code, hold, value, severity, message) {
    const cfg = DEBOUNCE[code] || DEBOUNCE_DEFAULT;
    const bankDb = DB[bank] || (DB[bank] = {});
    let e = bankDb[code];
    if (!e) {
        e = { state: 'clear', candidate: 'clear', count: 0 };
        bankDb[code] = e;
    }
    const cand = hold ? 'active' : 'clear';
    if (cand === e.state) {
        e.candidate = cand;
        e.count = 0;
        if (hold) e.value = value;
        return;
    }
    if (cand === e.candidate) {
        e.count++;
    } else {
        e.candidate = cand;
        e.count = 1;
    }
    if (hold) e.value = value;
    const need = hold ? cfg.active : cfg.clear;
    if (e.count >= need) {
        if (hold) {
            e.state = 'active';
            e.since = NOW_ISO;
            alerts.push({
                ts: NOW_ISO, bank, severity, code, msg: message,
                value, since: NOW_ISO, state: 'active', debounceTicks: need
            });
        } else {
            const since = e.since;
            e.state = 'clear';
            delete e.since;
            alerts.push({
                ts: NOW_ISO, bank, severity: 'info', code,
                msg: 'cleared', value: null, since, state: 'cleared'
            });
        }
        e.count = 0;
    }
}

function event(bank, code, value, severity, message) {
    alerts.push({
        ts: NOW_ISO, bank, severity, code, msg: message,
        value, since: NOW_ISO, state: 'event'
    });
}

for (const bank of BANKS) {
    const s = STATE[bank];
    const get = (path) => (s && s[path]) ? num(s[path].value) : null;

    const hasData = !!s && Object.keys(s).length > 0;
    condition(bank, 'no_data', !hasData, null, 'alert', 'No data ever received from bank');
    if (!hasData) continue;

    let newestTs = 0;
    for (const k in s) if (s[k]._ts > newestTs) newestTs = s[k]._ts;
    const ageMs = NOW - newestTs;
    const ageS = Math.round(ageMs / 1000);
    condition(bank, 'comm_dropout', ageMs > TH.comm_dropout_ms, ageS, 'alert',
        `No update in ${ageS}s`);

    const cellMin   = get('cell_voltages/min');
    const cellMax   = get('cell_voltages/max');
    const cellAvg   = get('cell_voltages/average');
    const cellDelta = get('cell_voltages/delta');
    const minIdx    = get('cell_voltages/min_index');
    const maxIdx    = get('cell_voltages/max_index');

    if (cellDelta !== null) {
        const isAlertDelta = cellDelta >= TH.cell_delta_alert;
        const isWarnDelta  = !isAlertDelta && cellDelta >= TH.cell_delta_warn;
        condition(bank, 'cell_delta_alert', isAlertDelta, cellDelta, 'alert',
            `Cell delta ${(cellDelta*1000).toFixed(0)}mV >= ${TH.cell_delta_alert*1000}mV (cell ${maxIdx} high, cell ${minIdx} low)`);
        condition(bank, 'cell_delta_warn', isWarnDelta, cellDelta, 'warn',
            `Cell delta ${(cellDelta*1000).toFixed(0)}mV >= ${TH.cell_delta_warn*1000}mV (cell ${maxIdx} high, cell ${minIdx} low)`);
    }

    if (cellMin !== null) {
        condition(bank, 'cell_under', cellMin < TH.cell_min, cellMin, 'alert',
            `Cell ${minIdx} at ${cellMin.toFixed(3)}V below ${TH.cell_min}V`);
    }
    if (cellMax !== null) {
        condition(bank, 'cell_over', cellMax > TH.cell_max, cellMax, 'alert',
            `Cell ${maxIdx} at ${cellMax.toFixed(3)}V above ${TH.cell_max}V`);
    }

    if (cellAvg !== null) {
        for (let i = 1; i <= 16; i++) {
            const v = get('cell_voltages/' + i);
            if (v === null) {
                condition(bank, 'cell_outlier_' + i, false, null, 'warn', '');
                continue;
            }
            const dev = Math.abs(v - cellAvg);
            condition(bank, 'cell_outlier_' + i, dev > TH.cell_outlier, v, 'warn',
                `Cell ${i} at ${v.toFixed(3)}V deviates ${(dev*1000).toFixed(0)}mV from bank avg ${cellAvg.toFixed(3)}V`);
        }
    }

    for (const i of [1, 2]) {
        const t = get('temperatures/' + i);
        if (t === null) {
            condition(bank, 'temp_high_' + i, false, null, 'alert', '');
            condition(bank, 'temp_low_'  + i, false, null, 'alert', '');
            continue;
        }
        condition(bank, 'temp_high_' + i, t > TH.temp_max, t, 'alert',
            `Temp sensor ${i} at ${t.toFixed(1)}C above ${TH.temp_max}C`);
        condition(bank, 'temp_low_' + i, t < TH.temp_min, t, 'alert',
            `Temp sensor ${i} at ${t.toFixed(1)}C below ${TH.temp_min}C`);
    }

    const mosfetTemp = get('mosfet_status/temperature');
    if (mosfetTemp !== null) {
        condition(bank, 'mosfet_temp_high', mosfetTemp > TH.mosfet_temp_max, mosfetTemp, 'alert',
            `MOSFET temp ${mosfetTemp.toFixed(1)}C above ${TH.mosfet_temp_max}C`);
    }

    const swCharge = (s['switch/charge'] || {}).value;
    const swDisch  = (s['switch/discharge'] || {}).value;
    if (swCharge !== undefined) {
        condition(bank, 'switch_charge_off', String(swCharge) !== 'ON', swCharge, 'alert',
            `Charge switch is ${swCharge}`);
    }
    if (swDisch !== undefined) {
        condition(bank, 'switch_discharge_off', String(swDisch) !== 'ON', swDisch, 'alert',
            `Discharge switch is ${swDisch}`);
    }

    const uptime = get('bms/uptime');
    if (uptime !== null) {
        const prevUp = (PREV[bank] || {}).uptime;
        if (prevUp !== undefined && uptime < prevUp - 10000) {
            event(bank, 'bms_reboot', uptime, 'warn',
                `BMS uptime decreased: ${prevUp}ms -> ${uptime}ms (likely reboot)`);
        }
        PREV[bank] = PREV[bank] || {};
        PREV[bank].uptime = uptime;
    }

    const cycles = get('soc/num_cycles');
    if (cycles !== null) {
        const prevCyc = (PREV[bank] || {}).cycles;
        if (prevCyc !== undefined && cycles < prevCyc) {
            event(bank, 'cycles_reset', cycles, 'warn',
                `Cycle counter decreased: ${prevCyc} -> ${cycles}`);
        }
        PREV[bank] = PREV[bank] || {};
        PREV[bank].cycles = cycles;
    }

    const fields = {};
    const map = {
        soc_percent:     'soc/soc_percent',
        total_voltage:   'soc/total_voltage',
        current:         'soc/current',
        power:           'soc/power',
        balance_current: 'soc/balance_current',
        num_cycles:      'soc/num_cycles',
        cell_delta:      'cell_voltages/delta',
        cell_min:        'cell_voltages/min',
        cell_max:        'cell_voltages/max',
        cell_avg:        'cell_voltages/average',
        capacity_ah:     'mosfet_status/capacity_ah',
        mosfet_temp:     'mosfet_status/temperature',
        temp1:           'temperatures/1',
        temp2:           'temperatures/2'
    };
    for (const fk in map) {
        const v = get(map[fk]);
        if (v !== null) fields[fk] = v;
    }
    if (Object.keys(fields).length > 0) {
        points.push({
            measurement: 'bms_health',
            tags: { bank },
            fields,
            timestamp: NOW
        });
    }
}

flow.set('bms_debounce', DB);
flow.set('bms_prev', PREV);

const outAlerts = alerts.map(a => ({ topic: 'checkbattery/alert', payload: a }));
const outInflux = points.length > 0 ? { payload: points } : null;
return [outAlerts, outInflux];

// Trend evaluator. Receives raw InfluxDB query result on msg.payload:
//   SELECT MEDIAN(cell_delta) FROM bms_health
//   WHERE time > now() - 24h GROUP BY time(1h), bank FILL(none)
// Per bank, fits a linear regression to the hourly medians. Emits a
// `trend_cell_delta_growth` event when slope exceeds threshold (mV/day).
// Needs >= 6 hourly buckets to fire — earlier hours just no-op.

const TH_SLOPE_MV_PER_DAY = 5;
const NOW_ISO = new Date().toISOString();

const data = msg.payload;
let series = [];
if (data && data.results && data.results[0] && Array.isArray(data.results[0].series)) {
    series = data.results[0].series;
} else if (Array.isArray(data) && data[0] && data[0].series) {
    series = data[0].series;
}
if (!series.length) {
    node.warn('trend_eval: no series in payload');
    return null;
}

const out = [];
for (const ser of series) {
    const bank = ser.tags && ser.tags.bank;
    if (!bank) continue;
    const cols = ser.columns || [];
    const tIdx = cols.indexOf('time');
    let mIdx = cols.indexOf('median');
    if (mIdx < 0) mIdx = cols.findIndex(c => typeof c === 'string' && c.indexOf('median') === 0);
    if (tIdx < 0 || mIdx < 0) continue;

    const pts = [];
    for (const row of ser.values || []) {
        const t = new Date(row[tIdx]).getTime();
        const m = parseFloat(row[mIdx]);
        if (Number.isFinite(m) && Number.isFinite(t)) pts.push([t, m]);
    }
    if (pts.length < 6) continue;

    const t0 = pts[0][0];
    let n = 0, sx = 0, sy = 0, sxx = 0, sxy = 0;
    for (const p of pts) {
        const x = (p[0] - t0) / 3600000;
        n++; sx += x; sy += p[1]; sxx += x*x; sxy += x*p[1];
    }
    const denom = n*sxx - sx*sx;
    if (denom === 0) continue;
    const slopeVPerHr = (n*sxy - sx*sy) / denom;
    const slopeMvPerDay = slopeVPerHr * 24 * 1000;

    if (slopeMvPerDay > TH_SLOPE_MV_PER_DAY) {
        out.push({
            topic: 'checkbattery/alert',
            payload: {
                ts: NOW_ISO,
                bank,
                severity: 'warn',
                code: 'trend_cell_delta_growth',
                msg: `cell_delta median trending +${slopeMvPerDay.toFixed(2)} mV/day over last 24h (n=${n} hourly buckets)`,
                value: slopeMvPerDay,
                since: NOW_ISO,
                state: 'event'
            }
        });
    }
}
return [out];

const NOW = Date.now();
const NOW_ISO = new Date(NOW).toISOString();
const BANKS = ['bat_ost', 'bat_west', 'bat_big'];
const TH = {
    cell_delta_warn:  0.050,
    cell_delta_alert: 0.100,
    cell_min:         2.80,
    cell_max:         3.60,
    cell_outlier:     0.030,
    temp_min:         -10,
    temp_max:         50,
    mosfet_temp_max:  60,
    comm_dropout_ms:  3 * 60 * 1000
};
const STATE = flow.get('bms_state') || {};

function num(v) {
    if (v === undefined || v === null) return null;
    const n = parseFloat(v);
    return Number.isFinite(n) ? n : null;
}

function build(bank) {
    const s = STATE[bank];
    if (!s || !Object.keys(s).length) {
        return { bank, hasData: false, ts: NOW_ISO, ageS: null, stale: true };
    }
    const g = (path) => (s[path] ? num(s[path].value) : null);
    const raw = (path) => (s[path] ? s[path].value : null);

    let newestTs = 0;
    for (const k in s) if (s[k]._ts > newestTs) newestTs = s[k]._ts;
    const ageMs = NOW - newestTs;
    const stale = ageMs > TH.comm_dropout_ms;

    const cellAvg = g('cell_voltages/average');
    const cellMin = g('cell_voltages/min');
    const cellMax = g('cell_voltages/max');
    const cellDelta = g('cell_voltages/delta');
    const minIdx = g('cell_voltages/min_index');
    const maxIdx = g('cell_voltages/max_index');

    const cells = [];
    for (let i = 1; i <= 16; i++) {
        const v = g('cell_voltages/' + i);
        let sev = 'na';
        let devMv = null;
        if (v !== null) {
            sev = 'ok';
            if (cellAvg !== null) {
                devMv = Math.round((v - cellAvg) * 1000);
                if (Math.abs(v - cellAvg) > TH.cell_outlier) sev = 'warn';
            }
            if (v < TH.cell_min || v > TH.cell_max) sev = 'crit';
        }
        cells.push({ i, v, devMv, sev, isMin: i === minIdx, isMax: i === maxIdx });
    }

    const t1 = g('temperatures/1');
    const t2 = g('temperatures/2');
    const mt = g('mosfet_status/temperature');
    const tempSev = (t) => t === null ? 'na' : (t < TH.temp_min || t > TH.temp_max ? 'crit' : 'ok');
    const mosfetSev = mt === null ? 'na' : (mt > TH.mosfet_temp_max ? 'crit' : 'ok');

    let deltaSev = 'na';
    if (cellDelta !== null) {
        deltaSev = 'ok';
        if (cellDelta >= TH.cell_delta_warn) deltaSev = 'warn';
        if (cellDelta >= TH.cell_delta_alert) deltaSev = 'crit';
    }

    const swCharge = raw('switch/charge');
    const swDisch  = raw('switch/discharge');
    const swBal    = raw('switch/balance');
    const swSev = (sw) => sw == null ? 'na' : (String(sw) === 'ON' ? 'ok' : 'crit');

    return {
        bank, hasData: true, ts: NOW_ISO,
        ageS: Math.round(ageMs / 1000), stale,
        soc: g('soc/soc_percent'),
        voltage: g('soc/total_voltage'),
        current: g('soc/current'),
        power: g('soc/power'),
        cycles: g('soc/num_cycles'),
        t1, t2, mt,
        tempSev1: tempSev(t1),
        tempSev2: tempSev(t2),
        mosfetSev,
        cellAvg, cellMin, cellMax, cellDelta,
        deltaSev, minIdx, maxIdx, cells,
        swCharge, swDisch, swBal,
        swChargeSev: swSev(swCharge),
        swDischSev:  swSev(swDisch),
        swBalSev:    swSev(swBal)
    };
}

return [
    { topic: 'bat_ost',  payload: build('bat_ost')  },
    { topic: 'bat_west', payload: build('bat_west') },
    { topic: 'bat_big',  payload: build('bat_big')  }
];

// Format InfluxDB raw output into ui_chart reload payload, per bank.
// Query: SELECT MEAN(cell_min) AS cmin, MEAN(cell_max) AS cmax
//        FROM bms_health WHERE time > now() - 48h
//        GROUP BY time(15m), bank FILL(none)
// Legend labels include the latest responsible cell index from
// flow.bms_state, e.g. "min (cell 8)" / "max (cell 2)".

const data = msg.payload;
let series = [];
if (data && data.results && data.results[0] && Array.isArray(data.results[0].series)) {
    series = data.results[0].series;
} else if (Array.isArray(data) && data[0] && data[0].series) {
    series = data[0].series;
}

const STATE = flow.get('bms_state') || {};

function currentIdx(bank, which) {
    const s = STATE[bank];
    if (!s) return null;
    const entry = s['cell_voltages/' + which + '_index'];
    if (!entry) return null;
    const n = parseInt(entry.value, 10);
    return Number.isFinite(n) ? n : null;
}

const banks = {
    bat_ost:  { min: [], max: [] },
    bat_west: { min: [], max: [] },
    bat_big:  { min: [], max: [] }
};

for (const ser of series) {
    const bank = ser.tags && ser.tags.bank;
    if (!banks[bank]) continue;
    const cols = ser.columns || [];
    const tIdx = cols.indexOf('time');
    const minIdx = cols.indexOf('cmin');
    const maxIdx = cols.indexOf('cmax');
    if (tIdx < 0) continue;
    for (const row of ser.values || []) {
        const t = new Date(row[tIdx]).getTime();
        if (!Number.isFinite(t)) continue;
        if (minIdx >= 0) {
            const v = parseFloat(row[minIdx]);
            if (Number.isFinite(v)) banks[bank].min.push({ x: t, y: v });
        }
        if (maxIdx >= 0) {
            const v = parseFloat(row[maxIdx]);
            if (Number.isFinite(v)) banks[bank].max.push({ x: t, y: v });
        }
    }
}

function label(prefix, idx) {
    return idx != null ? `${prefix} (cell ${idx})` : prefix;
}

function chartMsg(bank) {
    const mi = currentIdx(bank, 'min');
    const xi = currentIdx(bank, 'max');
    return {
        topic: bank,
        payload: [{
            series: [label('min', mi), label('max', xi)],
            data:   [banks[bank].min, banks[bank].max],
            labels: ['']
        }]
    };
}

return [chartMsg('bat_ost'), chartMsg('bat_west'), chartMsg('bat_big')];
